import{c as a,Q as r,j as s,m as n}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"性能诊断:lag 来源、profiler 与优化生态","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/19-性能诊断-lag来源profiler与优化生态.md","filePath":"minecraftLearning/19-性能诊断-lag来源profiler与优化生态.md","lastUpdated":1781676649000}'),e={name:"minecraftLearning/19-性能诊断-lag来源profiler与优化生态.md"};function o(d,t,i,p,l,c){return r(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="性能诊断-lag-来源、profiler-与优化生态" tabindex="-1">性能诊断:lag 来源、profiler 与优化生态 <a class="header-anchor" href="#性能诊断-lag-来源、profiler-与优化生态" aria-label="Permalink to &quot;性能诊断:lag 来源、profiler 与优化生态&quot;">​</a></h1><p>前面十几篇里,&quot;XX 是性能热点&quot;这句话反复出现——漏斗、实体、光照、随机刻、区块加载。这一篇把它们收口:Minecraft 的卡到底卡在哪、怎么测出来、以及社区那套优化 mod 各自治的是哪一段病。</p><blockquote><p>一句话先记住:<strong>先分清你卡的是 TPS 还是 FPS,这是两台完全不同的机器在喘气;然后用 profiler 看火焰图找真正的热点,而不是凭直觉关东西。</strong></p></blockquote><hr><h2 id="一、先把-卡-拆成两台机器" tabindex="-1">一、先把&quot;卡&quot;拆成两台机器 <a class="header-anchor" href="#一、先把-卡-拆成两台机器" aria-label="Permalink to &quot;一、先把&quot;卡&quot;拆成两台机器&quot;">​</a></h2><p>新手最容易犯的错:看到游戏卡,就一股脑去关材质、调画质。但服务端逻辑和客户端渲染是两套独立时钟(第 04 篇讲过),卡的根因可能在任意一边:</p><table tabindex="0"><thead><tr><th>指标</th><th>衡量谁</th><th>正常值</th><th>卡了的表现</th></tr></thead><tbody><tr><td><strong>TPS</strong> (ticks per second)</td><td>服务端逻辑循环</td><td>20</td><td>怪物动得慢、作物长得慢、红石变慢、被击退&quot;瞬移&quot;</td></tr><tr><td><strong>MSPT</strong> (毫秒/tick)</td><td>单 tick 耗时</td><td>&lt; 50ms</td><td>超过 50ms 就追不上 20 TPS,开始掉</td></tr><tr><td><strong>FPS</strong> (frames per second)</td><td>客户端渲染</td><td>越高越好</td><td>画面卡顿、掉帧,但游戏逻辑可能完全正常</td></tr></tbody></table><p>关键认知:</p><ul><li><strong>TPS 掉 ≠ FPS 掉</strong>。你可能 FPS 200 但 TPS 只有 8(服务端被一堆实体拖死),也可能 TPS 满 20 但 FPS 30(显卡画不动)。两者各查各的。</li><li><strong>MSPT 比 TPS 更有用</strong>。TPS 封顶 20,你看不出&quot;还剩多少余量&quot;。MSPT 35ms 和 48ms 都显示 TPS 20,但后者已经命悬一线。盯 MSPT,不要等 TPS 掉了才反应。</li></ul><blockquote><p>反直觉:很多人&quot;感觉服务器卡&quot;时,真正掉的是 FPS;反过来,联机时&quot;打怪像在水里挥拳&quot;才是典型的 TPS 病。先确认是哪台机器,再动手。</p></blockquote><hr><h2 id="二、tps-掉了-通常是这几类在吃-tick" tabindex="-1">二、TPS 掉了,通常是这几类在吃 tick <a class="header-anchor" href="#二、tps-掉了-通常是这几类在吃-tick" aria-label="Permalink to &quot;二、TPS 掉了,通常是这几类在吃 tick&quot;">​</a></h2><p>服务端每 tick 要把世界更新一遍(第 04 篇的执行顺序)。MSPT 超标,几乎都来自下面这几桶,按&quot;最常见、最坑&quot;排序:</p><table tabindex="0"><thead><tr><th>热点</th><th>为什么贵</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>实体过多</strong></td><td>每个实体每 tick 都要单独更新:AI 寻路(A*)、AABB 碰撞、计时(第 06 篇)</td><td>刷怪塔没关、海量掉落物堆地上、动物圈养过密</td></tr><tr><td><strong>block entity</strong></td><td>每 tick 遍历所有方块实体逐个 tick;漏斗每几 tick 还要扫容器内容(第 09 篇)</td><td>大型物流系统、几百个漏斗</td></tr><tr><td><strong>区块加载与生成</strong></td><td>生成是分阶段重计算(第 16 篇),加载要解压+反序列化(第 07/08 篇)</td><td>玩家高速移动、大量区块加载器、刚开荒的新地图</td></tr><tr><td><strong>随机刻</strong></td><td>randomTickSpeed 被调高,或大片作物/树叶都在 random tick(第 04 篇)</td><td>把 randomTickSpeed 拉到几千&quot;催熟&quot;的服务器</td></tr><tr><td><strong>光照更新</strong></td><td>放/挖方块触发光照洪水填充重算,原版光照引擎很拖(第 10 篇)</td><td>大规模建造/爆破、频繁开关光源</td></tr><tr><td><strong>复杂红石</strong></td><td>邻居更新级联可能引发&quot;更新风暴&quot;(第 14 篇)</td><td>大型红石机器、瞬时门、0-tick 农场</td></tr></tbody></table><p>经验法则:<strong>实体和 block entity 是 90% 服务器 lag 的来源</strong>。掉落物尤其阴险——一个没装满的物流系统会让物品堆在地上,每个掉落物都是一个要 tick 的实体。</p><hr><h2 id="三、别猜-用-profiler-看火焰图" tabindex="-1">三、别猜,用 profiler 看火焰图 <a class="header-anchor" href="#三、别猜-用-profiler-看火焰图" aria-label="Permalink to &quot;三、别猜,用 profiler 看火焰图&quot;">​</a></h2><p>&quot;我觉得是红石/我觉得是怪&quot;——这种猜测十次有八次错。Minecraft 这类系统,瓶颈往往反直觉地集中在一两个你没想到的地方。正确姿势是采样。</p><h3 id="spark-——-现在的事实标准" tabindex="-1">spark —— 现在的事实标准 <a class="header-anchor" href="#spark-——-现在的事实标准" aria-label="Permalink to &quot;spark —— 现在的事实标准&quot;">​</a></h3><p><a href="https://spark.lucko.me/" target="_blank" rel="noreferrer">spark</a> 是采样式 profiler(mod / 插件形态都有),核心用法:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/spark profiler start      # 开始采样</span></span>
<span class="line"><span>... 让卡顿场景持续一会儿 ...</span></span>
<span class="line"><span>/spark profiler stop       # 出报告,生成一个网页链接</span></span>
<span class="line"><span>/spark tps                 # 快速看 TPS / MSPT 当前值</span></span>
<span class="line"><span>/spark health              # 看内存、GC、MSPT 分布</span></span></code></pre></div><p>报告是一棵<strong>火焰图(调用栈采样)</strong>。怎么读:</p><ul><li>横向越宽 = 这段调用占的 tick 时间越多。<strong>先看最宽的那几条</strong>,那才是热点。</li><li>顺着宽条往下钻,直到看见具体的类/方法名:看到 <code>HopperBlockEntity</code> 就是漏斗,看到 <code>ServerLevel.tickChunk</code> 往下是 random tick 或刷怪,看到 <code>LevelLightEngine</code> 就是光照。</li><li>采样式(非插桩)意味着开销极小,可以在生产服上跑——这是它取代旧 Timings 的关键。</li></ul><h3 id="其它手段" tabindex="-1">其它手段 <a class="header-anchor" href="#其它手段" aria-label="Permalink to &quot;其它手段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>备注</th></tr></thead><tbody><tr><td><strong>/tick</strong> (1.21+)</td><td>原版内置:<code>/tick rate</code>、<code>/tick freeze</code>、<code>/tick step</code>、<code>/tick sprint</code></td><td>直接干预第 04 篇那个时间累加器,调试时冻结世界很好用</td></tr><tr><td><strong>F3 调试屏</strong></td><td>客户端:看 FPS、区块、实体计数、内存</td><td>偏客户端,服务端深度诊断还得靠 spark</td></tr><tr><td><strong>Timings</strong> (旧)</td><td>Paper 老一代服务端 profiler</td><td>基本被 spark 取代,新项目别用</td></tr></tbody></table><hr><h2 id="四、优化生态-每个-mod-治一段病" tabindex="-1">四、优化生态:每个 mod 治一段病 <a class="header-anchor" href="#四、优化生态-每个-mod-治一段病" aria-label="Permalink to &quot;四、优化生态:每个 mod 治一段病&quot;">​</a></h2><p>社区优化 mod 不是&quot;一键变快&quot;的玄学,每个都精准重写了某一段热点。知道它们各治什么,才能对症下药:</p><table tabindex="0"><thead><tr><th>mod</th><th>治哪段</th><th>对应前文</th></tr></thead><tbody><tr><td><strong>Lithium</strong></td><td>重写大量游戏逻辑算法(AI、碰撞、刷怪、区块 tick 调度),不改行为只改实现</td><td>第 04/06/15 篇</td></tr><tr><td><strong>Starlight</strong></td><td>把原版那套拖沓的光照引擎整个重写,放挖方块时的光照更新快几个数量级</td><td>第 10 篇</td></tr><tr><td><strong>C2ME</strong></td><td>并行化区块加载/生成,把单线程的生成流水线摊到多核</td><td>第 05/16 篇</td></tr><tr><td><strong>FerriteCore</strong></td><td>砍内存占用(BlockState、NBT 等的去重),降 GC 压力</td><td>第 08/09 篇</td></tr><tr><td><strong>Sodium</strong></td><td><strong>客户端</strong>渲染引擎重写,大幅提 FPS(这是 FPS 药,不是 TPS 药)</td><td>第 03/20 篇</td></tr></tbody></table><p>服务端形态的选择也是性能决策:</p><ul><li><strong>Paper</strong>(及其衍生)在原版基础上做了大量服务端优化和可配置项(实体活动范围、刷怪频率、漏斗节流等),纯生存服几乎默认起步。</li><li><strong>Fabric + Lithium/Starlight/C2ME</strong> 这条线更模块化,想保留 mod 生态时常走这边。</li></ul><blockquote><p>取舍提醒:Paper 这类为了性能,会<strong>牺牲一部分原版行为的精确性</strong>(某些机器、某些 tick 行为可能变样)。技术红石玩家反而要躲开这些&quot;优化&quot;,因为他们依赖的正是原版那套&quot;低效但确定&quot;的更新顺序(第 14 篇的 quasi-connectivity、更新顺序)。性能和行为保真,在 Minecraft 里是一对要权衡的目标。</p></blockquote><hr><h2 id="五、方法论-定位三步走" tabindex="-1">五、方法论:定位三步走 <a class="header-anchor" href="#五、方法论-定位三步走" aria-label="Permalink to &quot;五、方法论:定位三步走&quot;">​</a></h2><p>把上面串成一套不靠猜的流程:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 分清是哪台机器</span></span>
<span class="line"><span>   F3 看 FPS,/spark tps 看 TPS/MSPT —— 先确定卡在服务端还是客户端</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 采样找热点</span></span>
<span class="line"><span>   /spark profiler 跑出火焰图 —— 看最宽的调用栈,别先入为主</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 对症下药</span></span>
<span class="line"><span>   实体多 → 清掉落物 / 限刷怪 / 调 Paper 实体配置</span></span>
<span class="line"><span>   漏斗多 → 减 block entity / 上 Lithium</span></span>
<span class="line"><span>   光照卡 → Starlight</span></span>
<span class="line"><span>   生成卡 → C2ME / 降模拟距离(第 05 篇)</span></span>
<span class="line"><span>   红石风暴 → 改电路 / 接受它就是贵</span></span></code></pre></div><p>核心原则就一句:<strong>先测后改</strong>。Minecraft 的性能问题分布极不均匀,凭感觉关掉的东西,十有八九不是真正的瓶颈;而真正吃满 MSPT 的那个漏斗阵列,你不开火焰图永远不会想到。</p><hr><h2 id="串联" tabindex="-1">串联 <a class="header-anchor" href="#串联" aria-label="Permalink to &quot;串联&quot;">​</a></h2><p>这一篇是前面所有&quot;性能热点&quot;伏笔的总账:第 04 篇的 tick 预算、第 05 篇的 ticking 范围、第 06 篇的实体、第 09 篇的 block entity、第 10 篇的光照、第 14 篇的红石,在这里被统一到&quot;MSPT 怎么花&quot;这个视角下。下一步如果想往客户端钻,第 20 篇会把渲染管线(以及 Sodium 治的那段)讲透;想理解为什么生成会成为热点,回看第 16 篇的密度函数与结构生成。</p>`,40)])])}const u=a(e,[["render",o]]);export{g as __pageData,u as default};
